using System.Net; using System.Text.Json;
namespace ValoraPesquisa.Api.Middleware;
public sealed class ErrorHandlingMiddleware(RequestDelegate next,ILogger<ErrorHandlingMiddleware> logger){ public async Task Invoke(HttpContext ctx){ try{await next(ctx);} catch(UnauthorizedAccessException ex){await Write(ctx,HttpStatusCode.Forbidden,"FORBIDDEN",ex.Message);} catch(ArgumentException ex){await Write(ctx,HttpStatusCode.BadRequest,"VALIDATION_ERROR",ex.Message);} catch(Exception ex){logger.LogError(ex,"Unhandled {CorrelationId}",ctx.Items["CorrelationId"]); await Write(ctx,HttpStatusCode.InternalServerError,"UNEXPECTED_ERROR","Não foi possível concluir a operação.");}} static Task Write(HttpContext ctx,HttpStatusCode s,string code,string msg){ctx.Response.StatusCode=(int)s; ctx.Response.ContentType="application/json"; return ctx.Response.WriteAsync(JsonSerializer.Serialize(new{ok=false,code,message=msg,correlationId=ctx.Items["CorrelationId"]}));}}
